CREATE TABLE IF NOT EXISTS organizational_resilience_strategies (strategy_id TEXT PRIMARY KEY, strategy TEXT NOT NULL, domain TEXT NOT NULL, anticipation REAL NOT NULL, absorption REAL NOT NULL, adaptation REAL NOT NULL, learning REAL NOT NULL, memory REAL NOT NULL, coordination REAL NOT NULL, governance REAL NOT NULL, workforce_protection REAL NOT NULL, workforce_burden REAL NOT NULL, implementation_burden REAL NOT NULL, critical_function TEXT NOT NULL);
CREATE VIEW IF NOT EXISTS organizational_resilience_value_view AS SELECT strategy_id, strategy, domain, 0.11*anticipation + 0.11*absorption + 0.11*adaptation + 0.12*learning + 0.12*memory + 0.11*coordination + 0.11*governance + 0.12*workforce_protection - 0.05*workforce_burden - 0.04*implementation_burden AS organizational_resilience_value FROM organizational_resilience_strategies;
